import{_ as a,o as t,c as s,a3 as o}from"./chunks/framework.weVe1IXV.js";const h=JSON.parse('{"title":"Boas Práticas","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/guide/best-practices.md","filePath":"pt-BR/guide/best-practices.md"}'),r={name:"pt-BR/guide/best-practices.md"};function n(i,e,d,l,p,c){return t(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="boas-praticas" tabindex="-1">Boas Práticas <a class="header-anchor" href="#boas-praticas" aria-label="Permalink to &quot;Boas Práticas&quot;">​</a></h1><p>Dicas práticas para extrair o máximo do Specialist Agent e Claude Code. São padrões validados em projetos reais — não conselhos genéricos.</p><h2 id="planejamento" tabindex="-1">Planejamento <a class="header-anchor" href="#planejamento" aria-label="Permalink to &quot;Planejamento&quot;">​</a></h2><h3 id="sempre-comece-em-modo-de-planejamento" tabindex="-1">Sempre Comece em Modo de Planejamento <a class="header-anchor" href="#sempre-comece-em-modo-de-planejamento" aria-label="Permalink to &quot;Sempre Comece em Modo de Planejamento&quot;">​</a></h3><p>Antes de escrever código, use o modo de planejamento ou <code>@planner</code> para definir o escopo. Isso evita desperdício de tokens em abordagens erradas.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Use @planner to plan the checkout flow with payments and email notifications&quot;</span></span></code></pre></div><p>Para escopos incertos, use <code>/discovery</code> primeiro — ele avalia viabilidade e dá um veredicto GO/NO-GO antes de qualquer código.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;/discovery — we need a referral system with rewards, tracking, and analytics&quot;</span></span></code></pre></div><h3 id="deixe-o-claude-te-entrevistar" tabindex="-1">Deixe o Claude Te Entrevistar <a class="header-anchor" href="#deixe-o-claude-te-entrevistar" aria-label="Permalink to &quot;Deixe o Claude Te Entrevistar&quot;">​</a></h3><p>Em vez de escrever um prompt longo, peça ao agente para te entrevistar. Isso revela requisitos que você perderia:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Use @analyst to interview me about the requirements for user onboarding&quot;</span></span></code></pre></div><p>O <code>@analyst</code> usa a ferramenta <code>AskUserQuestion</code> para fazer perguntas direcionadas antes de produzir especificações.</p><h3 id="planos-com-gates-por-fase" tabindex="-1">Planos com Gates por Fase <a class="header-anchor" href="#planos-com-gates-por-fase" aria-label="Permalink to &quot;Planos com Gates por Fase&quot;">​</a></h3><p>Quebre features complexas em fases com verificação em cada gate:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Fase 1: Modelo de dados + API → rodar testes → checkpoint</span></span>
<span class="line"><span>Fase 2: Componentes UI → rodar testes → checkpoint</span></span>
<span class="line"><span>Fase 3: Integração → rodar testes e2e → checkpoint</span></span></code></pre></div><p>Use <code>@executor</code> para gerenciamento automático de checkpoints e rastreamento de custos entre fases.</p><h2 id="gerenciamento-de-contexto" tabindex="-1">Gerenciamento de Contexto <a class="header-anchor" href="#gerenciamento-de-contexto" aria-label="Permalink to &quot;Gerenciamento de Contexto&quot;">​</a></h2><h3 id="compacte-a-50-—-nao-a-90" tabindex="-1">Compacte a 50% — Não a 90% <a class="header-anchor" href="#compacte-a-50-—-nao-a-90" aria-label="Permalink to &quot;Compacte a 50% — Não a 90%&quot;">​</a></h3><p>A qualidade do Claude Code degrada conforme o contexto enche. Não espere pelos avisos.</p><table tabindex="0"><thead><tr><th>Uso do Contexto</th><th>Qualidade</th><th>Ação</th></tr></thead><tbody><tr><td>0-50%</td><td>Ótima</td><td>Continue trabalhando</td></tr><tr><td>50-70%</td><td>Declinando</td><td>Execute <code>/compact</code> agora</td></tr><tr><td>70%+</td><td>Degradada</td><td><code>/compact</code> ou <code>/clear</code> e recomece</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Vantagem do Specialist Agent</p><p>O <code>@orchestrator</code> evita esse problema completamente — cada subagente recebe contexto limpo via <strong>Context Isolation Protocol</strong>. Uma orquestração de 5 agentes nunca atinge limites de contexto.</p></div><h3 id="um-agente-uma-tarefa" tabindex="-1">Um Agente, Uma Tarefa <a class="header-anchor" href="#um-agente-uma-tarefa" aria-label="Permalink to &quot;Um Agente, Uma Tarefa&quot;">​</a></h3><p>Não sobrecarregue uma única conversa com tarefas não relacionadas. Em vez disso:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Ruim — poluição de contexto</span></span>
<span class="line"><span>&quot;Build the auth module, then review the payments module, then debug the cart&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Bom — agentes focados</span></span>
<span class="line"><span>&quot;Use @builder to create the auth module&quot;        # conversa 1</span></span>
<span class="line"><span>&quot;Use @reviewer to review the payments module&quot;    # conversa 2</span></span>
<span class="line"><span>&quot;Use @doctor to investigate the cart bug&quot;        # conversa 3</span></span></code></pre></div><p>Para trabalho multi-parte em uma única sessão, use <code>@orchestrator</code> — ele cria subagentes isolados automaticamente.</p><h3 id="use-rename-e-resume-para-projetos-longos" tabindex="-1">Use /rename e /resume para Projetos Longos <a class="header-anchor" href="#use-rename-e-resume-para-projetos-longos" aria-label="Permalink to &quot;Use /rename e /resume para Projetos Longos&quot;">​</a></h3><p>Nomeie sessões importantes para poder voltar a elas:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/rename &quot;auth-module-v2&quot;</span></span>
<span class="line"><span># ... dias depois ...</span></span>
<span class="line"><span>/resume &quot;auth-module-v2&quot;</span></span></code></pre></div><h2 id="selecao-de-agentes" tabindex="-1">Seleção de Agentes <a class="header-anchor" href="#selecao-de-agentes" aria-label="Permalink to &quot;Seleção de Agentes&quot;">​</a></h2><h3 id="quando-usar-qual-agente" tabindex="-1">Quando Usar Qual Agente <a class="header-anchor" href="#quando-usar-qual-agente" aria-label="Permalink to &quot;Quando Usar Qual Agente&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Situação</th><th>Melhor Escolha</th><th>Por quê</th></tr></thead><tbody><tr><td>Escopo incerto</td><td><code>/discovery</code></td><td>Avalia viabilidade antes de gastar tokens</td></tr><tr><td>Precisa de plano</td><td><code>@planner</code></td><td>Fases estruturadas com critérios de aceitação</td></tr><tr><td>Tarefa simples de build</td><td><code>@builder</code></td><td>Execução direta, sem overhead</td></tr><tr><td>3+ tarefas paralelas</td><td><code>@orchestrator</code></td><td>Cria subagentes, previne conflitos</td></tr><tr><td>Execução complexa</td><td><code>@executor</code></td><td>Checkpoints, custo, quality gates</td></tr><tr><td>Código suspeito</td><td><code>@reviewer</code></td><td>Review 3-em-1 com checks automáticos</td></tr><tr><td>Algo quebrado</td><td><code>@doctor</code></td><td>Diagnóstico em 4 fases com evidência</td></tr><tr><td>Protótipo rápido</td><td><code>@builder</code> (Lite)</td><td>Mais rápido, barato, suficiente para iteração</td></tr></tbody></table><h3 id="full-vs-lite-—-matriz-de-decisao" tabindex="-1">Full vs Lite — Matriz de Decisão <a class="header-anchor" href="#full-vs-lite-—-matriz-de-decisao" aria-label="Permalink to &quot;Full vs Lite — Matriz de Decisão&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tarefa</th><th>Usar Full</th><th>Usar Lite</th></tr></thead><tbody><tr><td>PR review</td><td>Sim</td><td>Não</td></tr><tr><td>Migração</td><td>Sim</td><td>Não</td></tr><tr><td>Investigação de bug</td><td>Sim</td><td>Não</td></tr><tr><td>Scaffold de componente</td><td>Não</td><td>Sim</td></tr><tr><td>Mudança rápida de texto</td><td>Não</td><td>Sim</td></tr><tr><td>Protótipo</td><td>Não</td><td>Sim</td></tr><tr><td>Copy de marketing</td><td>Não</td><td>Sim</td></tr></tbody></table><h3 id="claude-code-puro-vs-agentes" tabindex="-1">Claude Code Puro vs Agentes <a class="header-anchor" href="#claude-code-puro-vs-agentes" aria-label="Permalink to &quot;Claude Code Puro vs Agentes&quot;">​</a></h3><p>Para tarefas simples de um único arquivo, Claude Code puro (sem agente) costuma ser mais rápido:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Não precisa de agente — só pergunte diretamente</span></span>
<span class="line"><span>&quot;Add a loading spinner to the LoginButton component&quot;</span></span>
<span class="line"><span>&quot;Fix the typo in the error message on line 42&quot;</span></span>
<span class="line"><span>&quot;Add TypeScript types to this function&quot;</span></span></code></pre></div><p>Use agentes quando a tarefa envolve <strong>múltiplos arquivos</strong>, <strong>passos de verificação</strong>, ou <strong>expertise de domínio</strong> (segurança, performance, pagamentos).</p><h2 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-label="Permalink to &quot;Debugging&quot;">​</a></h2><h3 id="compartilhe-screenshots" tabindex="-1">Compartilhe Screenshots <a class="header-anchor" href="#compartilhe-screenshots" aria-label="Permalink to &quot;Compartilhe Screenshots&quot;">​</a></h3><p>Quando travar em bugs visuais, tire um screenshot e compartilhe com o Claude. Contexto visual resolve problemas mais rápido do que descrevê-los:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Here&#39;s a screenshot of the layout bug — the sidebar overlaps the main content on mobile&quot;</span></span></code></pre></div><h3 id="use-mcp-para-debug-no-browser" tabindex="-1">Use MCP para Debug no Browser <a class="header-anchor" href="#use-mcp-para-debug-no-browser" aria-label="Permalink to &quot;Use MCP para Debug no Browser&quot;">​</a></h3><p>Conecte ferramentas de browser via MCP para que agentes vejam logs do console e erros de rede diretamente:</p><table tabindex="0"><thead><tr><th>MCP</th><th>O que dá aos Agentes</th></tr></thead><tbody><tr><td><strong>Playwright</strong></td><td>Testes automatizados de browser, screenshots</td></tr><tr><td><strong>Chrome DevTools</strong></td><td>Logs do console, aba de rede, inspeção DOM</td></tr></tbody></table><p>Veja <a href="/pr-preview/pr-73/pt-BR/guide/mcp-integrations.html#ferramentas-complementares">Integrações MCP</a> para configuração.</p><h3 id="execute-tarefas-em-background-para-debug-ao-vivo" tabindex="-1">Execute Tarefas em Background para Debug ao Vivo <a class="header-anchor" href="#execute-tarefas-em-background-para-debug-ao-vivo" aria-label="Permalink to &quot;Execute Tarefas em Background para Debug ao Vivo&quot;">​</a></h3><p>Peça ao Claude para rodar o dev server como tarefa em background, depois debugue contra ele:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Run the dev server in background, then test the login flow and check for errors&quot;</span></span></code></pre></div><h2 id="otimizacao-de-custos" tabindex="-1">Otimização de Custos <a class="header-anchor" href="#otimizacao-de-custos" aria-label="Permalink to &quot;Otimização de Custos&quot;">​</a></h2><h3 id="selecao-inteligente-de-modelo" tabindex="-1">Seleção Inteligente de Modelo <a class="header-anchor" href="#selecao-inteligente-de-modelo" aria-label="Permalink to &quot;Seleção Inteligente de Modelo&quot;">​</a></h3><p>O <code>@executor</code> seleciona automaticamente o modelo mais barato apropriado:</p><table tabindex="0"><thead><tr><th>Tipo de Tarefa</th><th>Modelo</th><th>Por quê</th></tr></thead><tbody><tr><td>Boilerplate, CRUD, templates</td><td>Haiku</td><td>Rápido, barato, confiável para padrões simples</td></tr><tr><td>Lógica de negócio, componentes</td><td>Sonnet</td><td>Bom equilíbrio de qualidade e custo</td></tr><tr><td>Arquitetura, debug complexo</td><td>Opus</td><td>Máximo raciocínio para problemas difíceis</td></tr></tbody></table><h3 id="estime-antes-de-executar" tabindex="-1">Estime Antes de Executar <a class="header-anchor" href="#estime-antes-de-executar" aria-label="Permalink to &quot;Estime Antes de Executar&quot;">​</a></h3><p>Use <code>/estimate</code> antes de operações caras:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;/estimate — migrate 15 Vue 2 components to Vue 3 Composition API&quot;</span></span></code></pre></div><p>Isso dá projeções de tokens e custo antes de se comprometer.</p><h3 id="faca-checkpoints-com-frequencia" tabindex="-1">Faça Checkpoints com Frequência <a class="header-anchor" href="#faca-checkpoints-com-frequencia" aria-label="Permalink to &quot;Faça Checkpoints com Frequência&quot;">​</a></h3><p>Checkpoints são seguro barato. Se um agente sair do caminho, <code>Esc Esc</code> ou <code>/rewind</code> te leva de volta instantaneamente em vez de refazer trabalho.</p><p>O <code>@executor</code> cria checkpoints automaticamente após cada tarefa. Para trabalho manual, faça commits frequentes — pelo menos uma vez por hora de trabalho.</p><h2 id="workflows-multi-agente" tabindex="-1">Workflows Multi-Agente <a class="header-anchor" href="#workflows-multi-agente" aria-label="Permalink to &quot;Workflows Multi-Agente&quot;">​</a></h2><h3 id="sempre-planeje-antes-de-orquestrar" tabindex="-1">Sempre Planeje Antes de Orquestrar <a class="header-anchor" href="#sempre-planeje-antes-de-orquestrar" aria-label="Permalink to &quot;Sempre Planeje Antes de Orquestrar&quot;">​</a></h3><p>Nunca pule para <code>@orchestrator</code> sem um plano:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Ruim — orquestrador sem direção</span></span>
<span class="line"><span>&quot;Use @orchestrator to build the dashboard&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Bom — planeje primeiro, depois execute</span></span>
<span class="line"><span>&quot;Use @planner to plan the dashboard feature&quot;</span></span>
<span class="line"><span># ... revise o plano ...</span></span>
<span class="line"><span>&quot;Use @orchestrator to execute this plan&quot;</span></span></code></pre></div><h3 id="use-templates-de-handoff" tabindex="-1">Use Templates de Handoff <a class="header-anchor" href="#use-templates-de-handoff" aria-label="Permalink to &quot;Use Templates de Handoff&quot;">​</a></h3><p>Quando agentes passam trabalho entre si, handoffs estruturados previnem perda de contexto:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@builder completa → Standard Handoff → @reviewer recebe</span></span>
<span class="line"><span>@reviewer encontra bugs → QA FAIL Handoff → @builder recebe com issues específicos</span></span>
<span class="line"><span>@reviewer aprova → QA PASS Handoff → pronto para merge</span></span></code></pre></div><p><code>@orchestrator</code> e <code>@executor</code> usam esses templates automaticamente. Veja <a href="/pr-preview/pr-73/pt-BR/scenarios/workflows.html">Workflows Multi-Agente</a> para exemplos detalhados.</p><h3 id="verifique-nas-fronteiras" tabindex="-1">Verifique nas Fronteiras <a class="header-anchor" href="#verifique-nas-fronteiras" aria-label="Permalink to &quot;Verifique nas Fronteiras&quot;">​</a></h3><p>Toda transição entre agentes é um ponto potencial de falha. Sempre verifique após:</p><ol><li><code>@builder</code> termina → rodar testes antes de enviar para <code>@reviewer</code></li><li><code>@reviewer</code> aprova → rodar build completo antes de merge</li><li><code>@migrator</code> completa → rodar suite de testes original para verificar sem regressões</li></ol><p>Use <code>/verify</code> para garantir verificação baseada em evidências.</p><h2 id="configuracao" tabindex="-1">Configuração <a class="header-anchor" href="#configuracao" aria-label="Permalink to &quot;Configuração&quot;">​</a></h2><h3 id="mantenha-claude-md-abaixo-de-200-linhas" tabindex="-1">Mantenha CLAUDE.md Abaixo de 200 Linhas <a class="header-anchor" href="#mantenha-claude-md-abaixo-de-200-linhas" aria-label="Permalink to &quot;Mantenha CLAUDE.md Abaixo de 200 Linhas&quot;">​</a></h3><p>Um <code>CLAUDE.md</code> inchado desperdiça contexto em toda interação. Mantenha-o focado:</p><ul><li><strong>Inclua:</strong> Convenções específicas do projeto, estrutura de diretórios, decisões-chave</li><li><strong>Não inclua:</strong> Boas práticas genéricas, documentação de framework, regras óbvias</li></ul><p>Para regras detalhadas, use arquivos <code>.claude/rules/</code> — eles carregam sob demanda em vez de sempre.</p><h3 id="use-claude-rules-para-instrucoes-detalhadas" tabindex="-1">Use .claude/rules/ para Instruções Detalhadas <a class="header-anchor" href="#use-claude-rules-para-instrucoes-detalhadas" aria-label="Permalink to &quot;Use .claude/rules/ para Instruções Detalhadas&quot;">​</a></h3><p>Divida conjuntos grandes de instruções em arquivos por tópico:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.claude/rules/</span></span>
<span class="line"><span>  testing.md        # Convenções de teste</span></span>
<span class="line"><span>  api-patterns.md   # Regras de design de API</span></span>
<span class="line"><span>  naming.md         # Convenções de nomenclatura</span></span></code></pre></div><p>Estes carregam baseado em relevância de contexto, economizando tokens comparado a colocar tudo no <code>CLAUDE.md</code>.</p><h3 id="use-permissions-em-vez-de-dangerously-skip-permissions" tabindex="-1">Use /permissions em Vez de --dangerously-skip-permissions <a class="header-anchor" href="#use-permissions-em-vez-de-dangerously-skip-permissions" aria-label="Permalink to &quot;Use /permissions em Vez de --dangerously-skip-permissions&quot;">​</a></h3><p>Configure permissões granulares com sintaxe wildcard em vez de desabilitar segurança:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/permissions</span></span>
<span class="line"><span># Permitir leitura/escrita em src/</span></span>
<span class="line"><span># Permitir rodar npm test, npm run build</span></span>
<span class="line"><span># Bloquear rm -rf, git push --force</span></span></code></pre></div><h2 id="workflow-diario" tabindex="-1">Workflow Diário <a class="header-anchor" href="#workflow-diario" aria-label="Permalink to &quot;Workflow Diário&quot;">​</a></h2><h3 id="comece-sessoes-direito" tabindex="-1">Comece Sessões Direito <a class="header-anchor" href="#comece-sessoes-direito" aria-label="Permalink to &quot;Comece Sessões Direito&quot;">​</a></h3><ol><li>Verifique git status — working tree limpa antes de começar</li><li>Puxe últimas mudanças — <code>git pull</code> para evitar conflitos</li><li>Comece com modo de planejamento para features novas</li><li>Use <code>/onboard</code> ao voltar para código desconhecido</li></ol><h3 id="termine-sessoes-direito" tabindex="-1">Termine Sessões Direito <a class="header-anchor" href="#termine-sessoes-direito" aria-label="Permalink to &quot;Termine Sessões Direito&quot;">​</a></h3><ol><li>Commite trabalho em progresso — não perca mudanças</li><li>Rode testes — verifique que nada quebrou</li><li><code>/rename</code> a sessão se vai continuar depois</li><li>Anote itens abertos para a próxima sessão</li></ol><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-73/pt-BR/scenarios/workflows.html">Workflows Multi-Agente</a> — Exemplos reais de orquestração com estimativas de custo</li><li><a href="/pr-preview/pr-73/pt-BR/guide/agent-composition.html">Composição de Agentes</a> — Como agentes trabalham juntos</li><li><a href="/pr-preview/pr-73/pt-BR/guide/benchmark.html">Performance e Custo</a> — Otimização de uso de tokens</li><li><a href="/pr-preview/pr-73/pt-BR/guide/faq.html">FAQ</a> — Perguntas comuns respondidas</li></ul>`,90)])])}const m=a(r,[["render",n]]);export{h as __pageData,m as default};
